import { useState } from "react";
import MainHeaderTab from "./Tab";
import classes from "./TabBar.module.css";

const TabBar = () => {
  const [selectedTab, setSelectedTab] = useState("Online");

  const tabState = {
    selectedTab: selectedTab,
    setSelectedTab: setSelectedTab,
  };

  return (
    <div className={classes["tab-bar"]}>
      <MainHeaderTab link="/online" title="Online" tabState={tabState}></MainHeaderTab>
      <MainHeaderTab link="/all" title="All" tabState={tabState}></MainHeaderTab>
      <MainHeaderTab link="/pending" title="Pending" tabState={tabState}></MainHeaderTab>
      <MainHeaderTab link="/blocked" title="Blocked" tabState={tabState}></MainHeaderTab>
      <MainHeaderTab link="/add" title="Add Friend" tabState={tabState}></MainHeaderTab>
    </div>
  );
};

export default TabBar;
